<?php require __DIR__.'/../includes/bootstrap.php';$b=brands_schema_ready()?brand_by_slug(trim($_GET['slug']??'')):null;if(!$b){http_response_code(404);exit('Brand not found.');}$u=user();if($b['status']!=='approved'&&(!$u||!can_manage_brand($b,$u))){http_response_code(404);exit('Brand not found.');}$s=db()->prepare("SELECT u.display_name,u.username,bm.position_title FROM brand_members bm JOIN users u ON u.id=bm.user_id WHERE bm.brand_id=? AND bm.status='active' ORDER BY u.display_name");$s->execute([(int)$b['id']]);$members=$s->fetchAll();app_header($b['name']);$banner=$b['banner_path']?"background-image:linear-gradient(rgba(5,5,11,.18),rgba(5,5,11,.82)),url('".e(base_url($b['banner_path']))."')":'';?><section class="company-profile-hero" style="<?=$banner?>"><?php if($b['logo_path']):?><img class="company-profile-logo" src="<?=e(base_url($b['logo_path']))?>" alt=""><?php endif?><div><p class="eyebrow">BRAND · <a href="<?=e(base_url('company/view.php?slug='.urlencode($b['company_slug'])))?>"><?=e($b['company_name'])?></a></p><h1><?=e($b['name'])?></h1><p><?=e($b['short_description'])?></p></div></section><section class="profile-grid"><article class="app-card profile-main"><h2>About</h2><p><?=nl2br(e($b['description']?:'No description has been added yet.'))?></p><?php if($b['website']):?><a class="button primary" href="<?=e($b['website'])?>" target="_blank" rel="noopener">Visit Website</a><?php endif?></article><aside class="profile-side"><article class="app-card"><h2>Details</h2><dl><dt>Parent company</dt><dd><?=e($b['company_name'])?></dd><?php if($b['category']):?><dt>Category</dt><dd><?=e($b['category'])?></dd><?php endif?><?php if($b['founded_year']):?><dt>Founded</dt><dd><?=(int)$b['founded_year']?></dd><?php endif?></dl></article><?php if($members):?><article class="app-card"><h2>Team</h2><?php foreach($members as $m):?><p><a href="<?=e(base_url('profile.php?u='.urlencode($m['username'])))?>"><strong><?=e($m['display_name'])?></strong></a><br><span class="muted"><?=e($m['position_title'])?></span></p><?php endforeach?></article><?php endif?></aside></section><?php app_footer();
